question:
JavaScript で次のコードにある構文は何をしているか。

function greet() {
  console.log('こんにちは');
}

次のコードを実行すると、コンソールには何が出力されるか。

function greet() {
  console.log('こんにちは');
}
greet();

関数を呼び出すために必要な記述はどれか。

// greet という関数が定義済みとする
// 呼び出し方として正しいものを選べ

次の関数定義において、x と y は何と呼ばれるか。

function add(x, y) {
  return x + y;
}

次のコードを実行すると result の値はいくつになるか。

function add(x, y) {
  return x + y;
}
const result = add(3, 5);

次のコードを実行すると何が起こるか。

function sayHello() {
  console.log('Hello');
  return;
  console.log('World');
}

次のコードは何回 'Hello' を出力するか。

function greet() {
  console.log('Hello');
}
greet();
greet();
greet();

次のコードで result の値はいくつになるか。

function multiply(a, b) {
  return a * b;
}
const result = multiply(multiply(2, 3), 4);

次のコードはエラーになるか、正常に動くか。

console.log(square(5));
function square(n) {
  return n * n;
}

デフォルト引数を使った次の関数で、greet() と呼び出したときの出力はどれか。

function greet(name = 'ゲスト') {
  console.log('こんにちは、' + name + 'さん');
}

デフォルト引数の動作として正しい説明はどれか。

function calc(x, y = 10) {
  return x + y;
}
console.log(calc(5, null));

次のコードを実行すると result の値はいくつになるか。

const double = function(n) {
  return n * 2;
};
const result = double(7);

次のコードはエラーになるか、正常に動くか。

console.log(triple(4));
const triple = function(n) {
  return n * 3;
};

次のコードで、f を呼び出す2つの方法 f() と g() の違いはどれか。

function original() {
  return 42;
}
const f = original;
const g = original();

次のコードを実行すると result の値はいくつになるか。

function add(a, b) {
  return a + b;
}
function square(n) {
  return n * n;
}
const result = square(add(2, 3));

次のコードを実行すると output の値はいくつになるか。

function increment(n) {
  return n + 1;
}
let x = 5;
let output = increment(x) + increment(increment(x));

次のコードを実行したとき、最終的に result に代入される値はいくつか。

function apply(fn, value) {
  return fn(value);
}
function triple(n) {
  return n * 3;
}
const result = apply(triple, 7);

次のコードを実行すると何が出力されるか。

function outer(x) {
  function inner(y) {
    return x + y;
  }
  return inner(10);
}
console.log(outer(5));

次のコードで result の値はいくつになるか。

function makeAdder(x) {
  return function(y) {
    return x + y;
  };
}
const add5 = makeAdder(5);
const result = add5(3);

次のコードを実行するとコンソールに出力される値は何か。

function calc(a, b, op) {
  return op(a, b);
}
const result = calc(10, 4, function(x, y) { return x - y; });
console.log(result);

次のコードで、最終的に出力されるのはどれか。

function modify(arr) {
  arr.push(99);
}
const nums = [1, 2, 3];
modify(nums);
console.log(nums);

次のコードで output に代入される値はいくつか。

function compute(n) {
  if (n <= 0) return 0;
  return n + compute(n - 1);
}
const output = compute(4);

次のコードで a と b の値はそれぞれいくつになるか。

function swap(x, y) {
  let temp = x;
  x = y;
  y = temp;
}
let a = 10;
let b = 20;
swap(a, b);
console.log(a, b);

次のコードで result の値はいくつになるか。

function run(fn) {
  return fn() + fn();
}
let count = 0;
const result = run(function() {
  count++;
  return count;
});

次のコードで最終的に log に格納される値はいくつか。

function identity(x) {
  return x;
}
function compose(f, g) {
  return function(x) {
    return f(g(x));
  };
}
const double = (n) => n * 2;
const inc = (n) => n + 1;
const transform = compose(double, inc);
const log = transform(4);

次のコードで出力される値はどれか。

function makeCounter() {
  let count = 0;
  return function() {
    count++;
    return count;
  };
}
const counter1 = makeCounter();
const counter2 = makeCounter();
console.log(counter1());
console.log(counter1());
console.log(counter2());
